// React
import { reactEngine } from "@hushkey/howl-react";
new Howl({ engines: { react: reactEngine() } });

// Vue
import { vueEngine } from "@hushkey/howl-vue";
new Howl({ engines: { vue: vueEngine() } });

import type { ReactPageProps } from "@hushkey/howl-react";
import { useHead } from "@hushkey/howl-react/head";
import type { State } from "@howl/config";

export default function Post(props: ReactPageProps<unknown, State>) {
  const { slug } = props.params;

  useHead({
    title: `${slug} — Blog`,
    meta: [{ name: "description", content: `The ${slug} post` }],
  });

  return (
    <article>
      <h1>{slug}</h1>
      <p>Rendered on {props.url.pathname} for {props.state.title}.</p>
    </article>
  );
}

import { useEffect, useState } from "react";
import { http } from "../../../generated/http-client.ts"; // generated from apis/

export default function Items() {
  const [items, setItems] = useState([]);
  useEffect(() => {
    http.api.items.$get().then((res) => setItems(res.data));
  }, []);
  return <ul>{items.map((i) => <li key={i.id}>{i.name}</li>)}</ul>;
}

